import 'dart:convert';
import 'package:audioplayers/audioplayers.dart';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:shared_preferences/shared_preferences.dart';
import 'voice_note_recorder.dart';

// ── Lightweight rank item (mirrors _RankItem in users_screen.dart) ─────────

class _RankItem {
  final int id;
  final String username;
  final int? age;
  final String? sex;

  _RankItem({
    required this.id,
    required this.username,
    this.age,
    this.sex,
  });
}

// ── Profile screen ─────────────────────────────────────────────────────────

class ProfileScreen extends StatefulWidget {
  final int userId;
  final String username;
  final int age;
  final String sex;
  final String? sexuality;
  final String? bio;
  final int? height;
  final String? starSign;
  final String photoUrl;

  const ProfileScreen({
    super.key,
    required this.userId,
    required this.username,
    required this.age,
    required this.sex,
    this.sexuality,
    this.bio,
    this.height,
    this.starSign,
    required this.photoUrl,
  });

  @override
  State<ProfileScreen> createState() => _ProfileScreenState();
}

class _ProfileScreenState extends State<ProfileScreen> {
  static const String _baseUrl = 'http://10.0.2.2:8000';

  String? _token;
  bool _liked = false;

  @override
  void initState() {
    super.initState();
    _loadToken();
  }

  Future<void> _loadToken() async {
    final prefs = await SharedPreferences.getInstance();
    if (mounted) {
      setState(() => _token = prefs.getString('jwt_token'));
    }
  }

  Map<String, String> get _headers => {
        'Content-Type': 'application/json',
        if (_token != null) 'Authorization': 'Bearer $_token',
      };

  Future<void> _blockUser() async {
    try {
      final resp = await http.post(
        Uri.parse('$_baseUrl/api/block'),
        headers: _headers,
        body: jsonEncode({'blocked_user_id': widget.userId}),
      );
      if ((resp.statusCode == 200 || resp.statusCode == 201) && mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Blocked')),
        );
        Navigator.of(context).pop();
      }
    } catch (_) {}
  }

  Future<List<_RankItem>> _fetchWhoILike() async {
    try {
      final resp = await http.get(
        Uri.parse('$_baseUrl/api/who_i_like'),
        headers: _headers,
      );
      if (resp.statusCode == 200) {
        final data = jsonDecode(resp.body) as Map<String, dynamic>;
        final users =
            (data['users'] as List<dynamic>).cast<Map<String, dynamic>>();
        return users
            .map((u) => _RankItem(
                  id: u['id'] as int,
                  username: u['username'] as String,
                  age: u['age'] as int?,
                  sex: u['sex'] as String?,
                ))
            .toList();
      }
    } catch (_) {}
    return [];
  }

  Future<void> _saveRerank(List<_RankItem> ranked) async {
    try {
      final rankings = ranked.asMap().entries.map((e) {
        return {'username': e.value.username, 'rank': e.key + 1};
      }).toList();
      await http.put(
        Uri.parse('$_baseUrl/api/like/rerank'),
        headers: _headers,
        body: jsonEncode({'rankings': rankings}),
      );
    } catch (_) {}
  }

  Future<void> _uploadVoiceNote(String filePath) async {
    try {
      final request = http.MultipartRequest(
        'POST',
        Uri.parse('$_baseUrl/api/like/${widget.userId}/voice'),
      );
      if (_token != null) {
        request.headers['Authorization'] = 'Bearer $_token';
      }
      request.files.add(await http.MultipartFile.fromPath(
        'file',
        filePath,
        filename: 'voice_note.m4a',
      ));
      await request.send();
    } catch (_) {}
  }

  Future<void> _likeUser() async {
    if (_liked) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Already liked')),
      );
      return;
    }

    if (!mounted) return;
    final audioPath = await showModalBottomSheet<String>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      builder: (ctx) => VoiceNoteRecorder(username: widget.username),
    );

    if (audioPath == null) return;

    try {
      final resp = await http.post(
        Uri.parse('$_baseUrl/api/like'),
        headers: _headers,
        body: jsonEncode({'liked_user_id': widget.userId}),
      );
      if (resp.statusCode == 200 || resp.statusCode == 201) {
        await _uploadVoiceNote(audioPath);

        final body = jsonDecode(resp.body) as Map<String, dynamic>;
        final status = body['status'] as String?;

        if (status == 'matched') {
          if (mounted) {
            ScaffoldMessenger.of(context).showSnackBar(
              const SnackBar(content: Text('🎉 It\'s a match!')),
            );
            Navigator.of(context).pop();
          }
        } else {
          setState(() => _liked = true);

          final currentLikes = await _fetchWhoILike();
          final withoutNew =
              currentLikes.where((u) => u.id != widget.userId).toList();
          final items = [
            ...withoutNew,
            _RankItem(
              id: widget.userId,
              username: widget.username,
              age: widget.age,
              sex: widget.sex,
            ),
          ];

          if (!mounted) return;
          await showModalBottomSheet<bool>(
            context: context,
            isScrollControlled: true,
            backgroundColor: const Color(0xFF0E0E0E),
            shape: const RoundedRectangleBorder(
              borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
            ),
            builder: (ctx) => _RankingSheet(
              items: items,
              newUserId: widget.userId,
              baseUrl: _baseUrl,
              token: _token,
              onSave: (reordered) async {
                await _saveRerank(reordered);
                Navigator.of(ctx).pop(true);
              },
            ),
          );
        }
      }
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(context)
            .showSnackBar(SnackBar(content: Text('Like failed: $e')));
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    final mq = MediaQuery.of(context);
    final screenHeight = mq.size.height;
    final photoHeight = screenHeight * 0.60;
    final safeTop = mq.padding.top;
    final safeBottom = mq.padding.bottom;

    return Scaffold(
      backgroundColor: const Color(0xFF0E0E0E),
      body: Stack(
        children: [
          // ── Layout column (photo + dark fill) ──────────────────────────
          Column(
            children: [
              // Photo section with overlays
              Stack(
                children: [
                  SizedBox(
                    width: double.infinity,
                    height: photoHeight,
                    child: _buildPhoto(),
                  ),
                  // Gradient: transparent → black over bottom 30% of photo
                  Positioned(
                    left: 0,
                    right: 0,
                    bottom: 0,
                    height: photoHeight * 0.40,
                    child: Container(
                      decoration: const BoxDecoration(
                        gradient: LinearGradient(
                          begin: Alignment.topCenter,
                          end: Alignment.bottomCenter,
                          colors: [Colors.transparent, Colors.black],
                        ),
                      ),
                    ),
                  ),
                  // Username + age/sex overlaid at bottom of photo
                  Positioned(
                    left: 20,
                    right: 20,
                    bottom: 24,
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        Text(
                          widget.username,
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 28,
                            fontWeight: FontWeight.bold,
                            shadows: [
                              Shadow(color: Colors.black87, blurRadius: 8)
                            ],
                          ),
                        ),
                        const SizedBox(height: 4),
                        Text(
                          '${widget.age} · ${widget.sex}',
                          style: TextStyle(
                            color: Colors.white.withOpacity(0.70),
                            fontSize: 16,
                            shadows: const [
                              Shadow(color: Colors.black87, blurRadius: 6)
                            ],
                          ),
                        ),
                        if (widget.starSign != null || widget.height != null || widget.sexuality != null) ...[  
                          const SizedBox(height: 4),
                          Wrap(
                            spacing: 8,
                            runSpacing: 4,
                            children: [
                              if (widget.starSign != null)
                                _InfoChip(text: '${_starSignEmoji(widget.starSign!)} ${widget.starSign!}'),
                              if (widget.height != null)
                                _InfoChip(text: '${widget.height} cm'),
                              if (widget.sexuality != null)
                                _InfoChip(text: widget.sexuality!),
                            ],
                          ),
                        ],
                        if (widget.bio != null && widget.bio!.isNotEmpty) ...[  
                          const SizedBox(height: 8),
                          Text(
                            widget.bio!,
                            style: TextStyle(
                              color: Colors.white.withOpacity(0.60),
                              fontSize: 13,
                              fontStyle: FontStyle.italic,
                              shadows: const [Shadow(color: Colors.black87, blurRadius: 6)],
                            ),
                            maxLines: 3,
                            overflow: TextOverflow.ellipsis,
                          ),
                        ],
                      ],
                    ),
                  ),
                ],
              ),
              // Dark fill below photo (action bar overlays this)
              Expanded(child: Container(color: const Color(0xFF0E0E0E))),
            ],
          ),

          // ── Back button ────────────────────────────────────────────────
          Positioned(
            top: safeTop + 8,
            left: 12,
            child: GestureDetector(
              onTap: () => Navigator.of(context).pop(),
              child: Container(
                padding: const EdgeInsets.all(8),
                decoration: BoxDecoration(
                  color: Colors.black.withOpacity(0.70),
                  shape: BoxShape.circle,
                  boxShadow: const [
                    BoxShadow(
                      color: Colors.black45,
                      blurRadius: 6,
                      offset: Offset(0, 2),
                    ),
                  ],
                ),
                child: const Icon(
                  Icons.arrow_back_ios_new,
                  color: Colors.white,
                  size: 22,
                ),
              ),
            ),
          ),

          // ── Bottom action bar ──────────────────────────────────────────
          Positioned(
            left: 0,
            right: 0,
            bottom: 0,
            child: Container(
              padding: EdgeInsets.fromLTRB(24, 20, 24, safeBottom + 20),
              decoration: BoxDecoration(
                color: Colors.black.withOpacity(0.85),
              ),
              child: Row(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  // X — block button
                  GestureDetector(
                    onTap: _blockUser,
                    child: Container(
                      width: 68,
                      height: 68,
                      decoration: BoxDecoration(
                        color: const Color(0xFF2A2A2A),
                        shape: BoxShape.circle,
                        border: Border.all(
                          color: Colors.red.withOpacity(0.45),
                          width: 1.5,
                        ),
                        boxShadow: [
                          BoxShadow(
                            color: Colors.black.withOpacity(0.4),
                            blurRadius: 8,
                            offset: const Offset(0, 3),
                          ),
                        ],
                      ),
                      child: const Icon(
                        Icons.close,
                        color: Colors.red,
                        size: 34,
                      ),
                    ),
                  ),
                  const SizedBox(width: 48),
                  // Heart — like button
                  GestureDetector(
                    onTap: _likeUser,
                    child: Container(
                      width: 68,
                      height: 68,
                      decoration: BoxDecoration(
                        shape: BoxShape.circle,
                        gradient: const LinearGradient(
                          begin: Alignment.topLeft,
                          end: Alignment.bottomRight,
                          colors: [Color(0xFFE53935), Color(0xFFE91E8C)],
                        ),
                        boxShadow: [
                          BoxShadow(
                            color: const Color(0xFFE53935).withOpacity(0.45),
                            blurRadius: 14,
                            offset: const Offset(0, 4),
                          ),
                        ],
                      ),
                      child: Icon(
                        _liked ? Icons.favorite : Icons.favorite_border,
                        color: Colors.white,
                        size: 34,
                      ),
                    ),
                  ),
                ],
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildPhoto() {
    if (widget.photoUrl.isNotEmpty) {
      return Image.network(
        widget.photoUrl,
        fit: BoxFit.cover,
        width: double.infinity,
        height: double.infinity,
        errorBuilder: (_, __, ___) => _placeholder(),
        loadingBuilder: (ctx, child, progress) {
          if (progress == null) return child;
          return _placeholder();
        },
      );
    }
    return _placeholder();
  }

  static String _starSignEmoji(String sign) {
    const map = {
      'Aries': '♈', 'Taurus': '♉', 'Gemini': '♊', 'Cancer': '♋',
      'Leo': '♌', 'Virgo': '♍', 'Libra': '♎', 'Scorpio': '♏',
      'Sagittarius': '♐', 'Capricorn': '♑', 'Aquarius': '♒', 'Pisces': '♓',
    };
    return map[sign] ?? sign;
  }

  Widget _placeholder() {
    return Container(
      color: Colors.blueAccent.withOpacity(0.15),
      child: Center(
        child: Text(
          widget.username.isNotEmpty ? widget.username[0].toUpperCase() : '?',
          style: const TextStyle(
            fontSize: 64,
            fontWeight: FontWeight.bold,
            color: Colors.blueAccent,
          ),
        ),
      ),
    );
  }
}

// ── Info chip ─────────────────────────────────────────────────────────────

class _InfoChip extends StatelessWidget {
  final String text;
  const _InfoChip({required this.text});

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
      decoration: BoxDecoration(
        color: Colors.black.withOpacity(0.55),
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: Colors.white24, width: 0.5),
      ),
      child: Text(
        text,
        style: const TextStyle(
          color: Colors.white,
          fontSize: 12,
          shadows: [Shadow(color: Colors.black87, blurRadius: 4)],
        ),
      ),
    );
  }
}

// ── Ranking bottom sheet ───────────────────────────────────────────────────

class _RankingSheet extends StatefulWidget {
  final List<_RankItem> items;
  final int newUserId;
  final String baseUrl;
  final String? token;
  final Future<void> Function(List<_RankItem>) onSave;

  const _RankingSheet({
    required this.items,
    required this.newUserId,
    required this.baseUrl,
    required this.token,
    required this.onSave,
  });

  @override
  State<_RankingSheet> createState() => _RankingSheetState();
}

class _RankingSheetState extends State<_RankingSheet> {
  late List<_RankItem> _items;
  bool _saving = false;
  final ScrollController _scrollController = ScrollController();
  final AudioPlayer _audioPlayer = AudioPlayer();
  final Map<int, bool> _playing = {};
  final Map<int, String?> _voiceUrls = {};
  final Map<int, Future<void>> _voiceFutures = {};

  static const _bg = Color(0xFF0E0E0E);

  static const _rankColors = [
    Color(0xFFFFC107),
    Color(0xFFFF5722),
    Color(0xFFE91E8C),
    Color(0xFF00BCD4),
    Color(0xFF8BC34A),
    Color(0xFF9C27B0),
    Color(0xFF03A9F4),
    Color(0xFFFF9800),
    Color(0xFF4CAF50),
    Color(0xFFF44336),
    Color(0xFF00E5FF),
    Color(0xFFCDDC39),
  ];

  @override
  void initState() {
    super.initState();
    _items = List.from(widget.items);
    _audioPlayer.onPlayerComplete.listen((_) {
      if (mounted) {
        setState(() {
          for (final k in _playing.keys.toList()) {
            _playing[k] = false;
          }
        });
      }
    });
    WidgetsBinding.instance.addPostFrameCallback((_) {
      final newIndex = _items.indexWhere((i) => i.id == widget.newUserId);
      if (newIndex > 0 && _scrollController.hasClients) {
        _scrollController.animateTo(
          newIndex * 72.0,
          duration: const Duration(milliseconds: 400),
          curve: Curves.easeOut,
        );
      }
    });
  }

  @override
  void dispose() {
    _audioPlayer.dispose();
    _scrollController.dispose();
    super.dispose();
  }

  Future<String?> _fetchVoiceUrl(int userId) async {
    try {
      final resp = await http.get(
        Uri.parse('${widget.baseUrl}/api/like/$userId/voice'),
        headers: {
          if (widget.token != null) 'Authorization': 'Bearer ${widget.token}',
        },
      );
      if (resp.statusCode == 200) {
        final data = jsonDecode(resp.body) as Map<String, dynamic>;
        return data['url'] as String?;
      }
    } catch (_) {}
    return null;
  }

  Future<void> _togglePlay(int userId) async {
    if (_playing[userId] == true) {
      await _audioPlayer.stop();
      setState(() => _playing[userId] = false);
      return;
    }

    if (!_voiceUrls.containsKey(userId)) {
      final url = await _fetchVoiceUrl(userId);
      setState(() => _voiceUrls[userId] = url);
    }

    final url = _voiceUrls[userId];
    if (url == null) return;

    await _audioPlayer.play(UrlSource(url));
    setState(() {
      for (final k in _playing.keys.toList()) {
        _playing[k] = false;
      }
      _playing[userId] = true;
    });
  }

  @override
  Widget build(BuildContext context) {
    final screenH = MediaQuery.of(context).size.height;

    return Container(
      height: screenH * 0.75,
      decoration: const BoxDecoration(
        color: _bg,
        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
      ),
      child: Column(
        children: [
          Container(
            margin: const EdgeInsets.only(top: 10, bottom: 4),
            width: 40,
            height: 4,
            decoration: BoxDecoration(
              color: Colors.white24,
              borderRadius: BorderRadius.circular(2),
            ),
          ),
          const Padding(
            padding: EdgeInsets.only(top: 12, bottom: 4),
            child: Text(
              'RANK YOUR LIKES',
              textAlign: TextAlign.center,
              style: TextStyle(
                color: Colors.white,
                fontSize: 18,
                fontWeight: FontWeight.bold,
                letterSpacing: 1.2,
              ),
            ),
          ),
          const Padding(
            padding: EdgeInsets.only(bottom: 10),
            child: Text(
              'Drag to prioritise — #1 is your top pick',
              style: TextStyle(color: Colors.white38, fontSize: 11),
            ),
          ),
          Expanded(
            child: ReorderableListView.builder(
              scrollController: _scrollController,
              padding: const EdgeInsets.only(bottom: 8),
              itemCount: _items.length,
              onReorder: (oldIndex, newIndex) {
                setState(() {
                  if (newIndex > oldIndex) newIndex--;
                  final item = _items.removeAt(oldIndex);
                  _items.insert(newIndex, item);
                });
              },
              itemBuilder: (ctx, index) {
                final item = _items[index];
                final isNew = item.id == widget.newUserId;
                final photoUrl =
                    '${widget.baseUrl}/api/users/${item.id}/photo';
                final rankColor = _rankColors[index % _rankColors.length];

                return ReorderableDragStartListener(
                  key: ValueKey(item.id),
                  index: index,
                  child: Container(
                    color: isNew
                        ? const Color(0xFFFFC107).withOpacity(0.08)
                        : _bg,
                    child: Column(
                      children: [
                        Padding(
                          padding: const EdgeInsets.symmetric(
                              horizontal: 16, vertical: 14),
                          child: Row(
                            children: [
                              SizedBox(
                                width: 36,
                                child: Text(
                                  '${index + 1}',
                                  style: TextStyle(
                                    color: rankColor,
                                    fontSize: 28,
                                    fontWeight: FontWeight.bold,
                                  ),
                                ),
                              ),
                              const SizedBox(width: 12),
                              CircleAvatar(
                                radius: 24,
                                backgroundColor: Colors.white12,
                                child: ClipOval(
                                  child: Image.network(
                                    photoUrl,
                                    width: 48,
                                    height: 48,
                                    fit: BoxFit.cover,
                                    headers: widget.token != null
                                        ? {'Authorization': 'Bearer ${widget.token}'}
                                        : {},
                                    errorBuilder: (_, __, ___) => Text(
                                      item.username.isNotEmpty
                                          ? item.username[0].toUpperCase()
                                          : '?',
                                      style: const TextStyle(
                                        color: Colors.white,
                                        fontSize: 18,
                                        fontWeight: FontWeight.bold,
                                      ),
                                    ),
                                  ),
                                ),
                              ),
                              const SizedBox(width: 14),
                              Expanded(
                                child: Column(
                                  crossAxisAlignment: CrossAxisAlignment.start,
                                  children: [
                                    Row(
                                      children: [
                                        Text(
                                          item.username,
                                          style: const TextStyle(
                                            color: Colors.white,
                                            fontSize: 16,
                                            fontWeight: FontWeight.bold,
                                          ),
                                        ),
                                        if (isNew) ...[
                                          const SizedBox(width: 6),
                                          Container(
                                            padding:
                                                const EdgeInsets.symmetric(
                                                    horizontal: 6, vertical: 2),
                                            decoration: BoxDecoration(
                                              color: const Color(0xFFFFC107),
                                              borderRadius:
                                                  BorderRadius.circular(4),
                                            ),
                                            child: const Text(
                                              'New',
                                              style: TextStyle(
                                                color: Colors.black,
                                                fontSize: 11,
                                                fontWeight: FontWeight.bold,
                                              ),
                                            ),
                                          ),
                                        ],
                                      ],
                                    ),
                                    if (item.age != null || item.sex != null)
                                      Text(
                                        [
                                          if (item.age != null) '${item.age}',
                                          if (item.sex != null) item.sex!,
                                        ].join(' · '),
                                        style: const TextStyle(
                                            color: Colors.white38,
                                            fontSize: 12),
                                      ),
                                  ],
                                ),
                              ),
                              FutureBuilder<void>(
                                future: _voiceFutures.putIfAbsent(
                                  item.id,
                                  () => _fetchVoiceUrl(item.id).then((url) {
                                    if (mounted) {
                                      setState(() => _voiceUrls[item.id] = url);
                                    }
                                  }),
                                ),
                                builder: (_, __) {
                                  final hasVoice =
                                      _voiceUrls.containsKey(item.id) &&
                                          _voiceUrls[item.id] != null;
                                  if (!hasVoice) return const SizedBox.shrink();
                                  final isPlaying = _playing[item.id] == true;
                                  return GestureDetector(
                                    onTap: () => _togglePlay(item.id),
                                    child: Container(
                                      width: 32,
                                      height: 32,
                                      margin: const EdgeInsets.only(right: 8),
