  final DateTime expiresAt;
  final int lockedUserId;
  final String lockedUsername;

  _DailyLockInfo({
    required this.id,
    required this.status,
    required this.expiresAt,
    required this.lockedUserId,
    required this.lockedUsername,
  });

  factory _DailyLockInfo.fromJson(Map<String, dynamic> json) {
    final lockedUser = (json['locked_user'] as Map<String, dynamic>?) ??
        (json['liked_user'] as Map<String, dynamic>?) ??
        {};
